{
  "output": {
    "reasoning": "Implicit edge cases: 1. Min > Max is logically impossible, should be rejected. 2. Negative prices may be invalid. Test invalid inputs BEFORE valid filter.",
    "ux_tasks": [
      {
        "number": 1,
        "requirement": "Verify app rejects impossible range (min greater than max)",
        "steps": [
          "Locate 'Min Price' input",
          "Type '500'",
          "Locate 'Max Price' input",
          "Type '100'",
          "Click 'Apply Filter' button",
          "Verify error message is visible",
          "Verify text 'Min must be less than Max' appears"
        ],
        "acceptance_criteria": "Error displayed indicating min must be less than max"
      },
      {
        "number": 2,
        "requirement": "Verify app rejects negative price values",
        "steps": [
          "Locate 'Min Price' input",
          "Type '-50'",
          "Click 'Apply Filter' button",
          "Verify error message is visible"
        ],
        "acceptance_criteria": "Error displayed indicating price cannot be negative"
      },
      {
        "number": 3,
        "requirement": "User applies valid price range filter",
        "steps": [
          "Locate 'Min Price' input",
          "Type '100'",
          "Locate 'Max Price' input",
          "Type '500'",
          "Click 'Apply Filter' button",
          "Verify results list updates",
          "Verify all visible items are within the 100-500 range"
        ],
        "acceptance_criteria": "Results show only items within price range"
      }
    ]
  }
}

{
  "output": {
    "reasoning": "Implicit edge cases: 1. Unauthenticated access to profile page should fail. 2. User should not edit another user's profile. Test these BEFORE the happy path.",
    "ux_tasks": [
      {
        "number": 1,
        "requirement": "Verify unauthenticated user cannot access profile page",
        "steps": [
          "Open new tab",
          "Navigate to '/profile'",
          "Verify current URL is '/login'",
          "Verify text 'Please log in' is visible"
        ],
        "acceptance_criteria": "User is redirected to login or sees 'Please log in' message"
      },
      {
        "number": 2,
        "requirement": "Verify user cannot edit another user's profile",
        "steps": [
          "Navigate to '/profile/other-user-id'",
          "Locate 'Edit Bio' button",
          "Verify element is hidden"
        ],
        "acceptance_criteria": "Edit functionality is not available for other users' profiles"
      },
      {
        "number": 3,
        "requirement": "User edits their own bio successfully",
        "steps": [
          "Navigate to '/profile'",
          "Click 'Edit Bio'",
          "Type 'New bio text'",
          "Click 'Save'",
          "Verify text 'Bio updated' is visible",
          "Verify text 'New bio text' is present on page"
        ],
        "acceptance_criteria": "Bio updated successfully"
      }
    ]
  }
}

{
  "output": {
    "reasoning": "Security check first. Negative test (Invalid Login) -> Positive test (Valid Login).",
    "ux_tasks": [
      {
        "number": 1,
        "requirement": "Verify login fails with invalid password",
        "steps": [
          "Type 'user@example.com' into 'Email'",
          "Type 'wrongpass' into 'Password'",
          "Click 'Login'",
          "Verify error message 'Invalid credentials' is visible"
        ],
        "acceptance_criteria": "Error displayed"
      },
      {
        "number": 2,
        "requirement": "User logs in successfully",
        "steps": [
          "Type 'user@example.com' into 'Email'",
          "Type 'correctpass' into 'Password'",
          "Click 'Login'",
          "Verify 'Dashboard' header is visible"
        ],
        "acceptance_criteria": "Dashboard visible"
      }
    ]
  }
}

